import{_ as a,o as t,c as o,ag as n}from"./chunks/framework.CnqOxlWO.js";const g=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"settings/faq.md","filePath":"settings/faq.md","lastUpdated":1773376681000}'),i={name:"settings/faq.md"};function r(s,e,h,l,d,c){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Common questions and troubleshooting tips, organized by topic.</p><h2 id="login-setup" tabindex="-1">Login &amp; Setup <a class="header-anchor" href="#login-setup" aria-label="Permalink to &quot;Login &amp; Setup&quot;">​</a></h2><h3 id="i-did-not-receive-the-magic-link-email" tabindex="-1">I did not receive the magic link email <a class="header-anchor" href="#i-did-not-receive-the-magic-link-email" aria-label="Permalink to &quot;I did not receive the magic link email&quot;">​</a></h3><ul><li>Check your spam or junk folder.</li><li>Verify you entered the correct email address.</li><li>Wait a minute and try again.</li></ul><h3 id="the-magic-link-does-not-open-the-app" tabindex="-1">The magic link does not open the app <a class="header-anchor" href="#the-magic-link-does-not-open-the-app" aria-label="Permalink to &quot;The magic link does not open the app&quot;">​</a></h3><p>Copy the full URL from the email and paste it into the input field on the login screen. See <a href="/clawdsaber-docs/getting-started/login.html">Login &amp; Registration</a> for details.</p><h3 id="the-magic-link-expired" tabindex="-1">The magic link expired <a class="header-anchor" href="#the-magic-link-expired" aria-label="Permalink to &quot;The magic link expired&quot;">​</a></h3><p>Magic links are valid for a limited time. Go back to the login screen and request a new one.</p><h3 id="the-environment-check-is-stuck" tabindex="-1">The environment check is stuck <a class="header-anchor" href="#the-environment-check-is-stuck" aria-label="Permalink to &quot;The environment check is stuck&quot;">​</a></h3><ul><li>Check your internet connection.</li><li>Restart ClawdSaber and try the setup wizard again.</li><li>If a specific component fails the check, follow the on-screen guidance to install or fix it.</li></ul><h2 id="chat-agents" tabindex="-1">Chat &amp; Agents <a class="header-anchor" href="#chat-agents" aria-label="Permalink to &quot;Chat &amp; Agents&quot;">​</a></h2><h3 id="the-chat-page-says-no-available-agent" tabindex="-1">The chat page says &quot;No available agent&quot; <a class="header-anchor" href="#the-chat-page-says-no-available-agent" aria-label="Permalink to &quot;The chat page says &quot;No available agent&quot;&quot;">​</a></h3><p>You have not created an agent yet. Go to the <a href="/clawdsaber-docs/features/templates-and-market.html">Template Library</a> or <a href="/clawdsaber-docs/features/templates-and-market.html">Agent Market</a> and create one.</p><h3 id="the-agent-does-not-respond-to-messages" tabindex="-1">The agent does not respond to messages <a class="header-anchor" href="#the-agent-does-not-respond-to-messages" aria-label="Permalink to &quot;The agent does not respond to messages&quot;">​</a></h3><p>This is the most common issue. Check these four things in order:</p><ol><li><strong>Model</strong> — Open the agent&#39;s settings and confirm a model is assigned. An agent without a model cannot reply. See <a href="/clawdsaber-docs/features/agent-config.html">Agent Configuration</a>.</li><li><strong>Gateway</strong> — Check the Gateway status indicator in the title bar. If it shows anything other than &quot;Running&quot;, the agent cannot process messages.</li><li><strong>Credits</strong> — Confirm your account has enough credits. If your balance is zero, top up on the <a href="/clawdsaber-docs/features/recharge.html">Recharge</a> page.</li><li><strong>Network</strong> — The Gateway needs an internet connection to reach the AI model provider.</li></ol><h3 id="can-i-send-files-in-chat" tabindex="-1">Can I send files in chat? <a class="header-anchor" href="#can-i-send-files-in-chat" aria-label="Permalink to &quot;Can I send files in chat?&quot;">​</a></h3><p>Yes. You can:</p><ul><li>Click the paperclip icon to select files</li><li>Drag files into the input area</li><li>Paste images directly</li></ul><p>Images show a preview before sending. Other files display their name and size.</p><h3 id="what-does-show-thinking-do" tabindex="-1">What does &quot;Show Thinking&quot; do? <a class="header-anchor" href="#what-does-show-thinking-do" aria-label="Permalink to &quot;What does &quot;Show Thinking&quot; do?&quot;">​</a></h3><p>It toggles the visibility of the model&#39;s internal reasoning process. When enabled, you may see thinking fragments, tool calls, and intermediate steps in the response.</p><p>Not every response includes thinking content.</p><h3 id="my-conversations-are-getting-messy" tabindex="-1">My conversations are getting messy <a class="header-anchor" href="#my-conversations-are-getting-messy" aria-label="Permalink to &quot;My conversations are getting messy&quot;">​</a></h3><p>Click <strong>New Session</strong> in the toolbar to start a fresh conversation. Each session maintains its own context independently.</p><h2 id="telegram" tabindex="-1">Telegram <a class="header-anchor" href="#telegram" aria-label="Permalink to &quot;Telegram&quot;">​</a></h2><h3 id="telegram-validation-failed" tabindex="-1">Telegram validation failed <a class="header-anchor" href="#telegram-validation-failed" aria-label="Permalink to &quot;Telegram validation failed&quot;">​</a></h3><ul><li>Confirm the Bot Token was copied from <code>@BotFather</code> without extra spaces.</li><li>Make sure the bot was created successfully in Telegram.</li><li>See <a href="/clawdsaber-docs/features/telegram.html">Telegram Integration</a> for the full setup guide.</li></ul><h3 id="i-set-allowed-users-but-it-does-not-work" tabindex="-1">I set allowed users but it does not work <a class="header-anchor" href="#i-set-allowed-users-but-it-does-not-work" aria-label="Permalink to &quot;I set allowed users but it does not work&quot;">​</a></h3><ul><li>Use commas to separate usernames: <code>alice,bob,charlie</code></li><li>Do not include the <code>@</code> prefix.</li><li>Verify the exact spelling of each username.</li></ul><h3 id="the-bot-is-connected-but-does-not-reply" tabindex="-1">The bot is connected but does not reply <a class="header-anchor" href="#the-bot-is-connected-but-does-not-reply" aria-label="Permalink to &quot;The bot is connected but does not reply&quot;">​</a></h3><p>Check in this order:</p><ol><li>Agent has a model assigned.</li><li>Gateway is running.</li><li>Account has credits.</li></ol><h3 id="how-do-i-find-my-telegram-username" tabindex="-1">How do I find my Telegram username? <a class="header-anchor" href="#how-do-i-find-my-telegram-username" aria-label="Permalink to &quot;How do I find my Telegram username?&quot;">​</a></h3><p>Open Telegram, go to <strong>Settings</strong>, and look for your username (starts with <code>@</code>). When entering it in ClawdSaber, omit the <code>@</code>.</p><h2 id="recharge" tabindex="-1">Recharge <a class="header-anchor" href="#recharge" aria-label="Permalink to &quot;Recharge&quot;">​</a></h2><h3 id="what-is-the-minimum-recharge-amount" tabindex="-1">What is the minimum recharge amount? <a class="header-anchor" href="#what-is-the-minimum-recharge-amount" aria-label="Permalink to &quot;What is the minimum recharge amount?&quot;">​</a></h3><p>1 USDT.</p><h3 id="what-network-should-i-use" tabindex="-1">What network should I use? <a class="header-anchor" href="#what-network-should-i-use" aria-label="Permalink to &quot;What network should I use?&quot;">​</a></h3><p>Always use the network displayed on the payment screen. Do not send from a different network.</p><h3 id="i-have-a-pending-order-—-can-i-create-a-new-one" tabindex="-1">I have a pending order — can I create a new one? <a class="header-anchor" href="#i-have-a-pending-order-—-can-i-create-a-new-one" aria-label="Permalink to &quot;I have a pending order — can I create a new one?&quot;">​</a></h3><p>If a previous order is still pending, the app will try to resume it when you return to the Recharge page. If the order has expired, you can create a new one.</p><h3 id="my-order-expired" tabindex="-1">My order expired <a class="header-anchor" href="#my-order-expired" aria-label="Permalink to &quot;My order expired&quot;">​</a></h3><p>Expired orders cannot be reused. Create a new order from the Recharge page.</p><h2 id="interface-settings" tabindex="-1">Interface &amp; Settings <a class="header-anchor" href="#interface-settings" aria-label="Permalink to &quot;Interface &amp; Settings&quot;">​</a></h2><h3 id="how-do-i-change-the-language" tabindex="-1">How do I change the language? <a class="header-anchor" href="#how-do-i-change-the-language" aria-label="Permalink to &quot;How do I change the language?&quot;">​</a></h3><p>Go to <strong>Settings &gt; Appearance &gt; Language</strong> and click your preferred language. The change applies immediately.</p><h3 id="how-do-i-check-for-updates" tabindex="-1">How do I check for updates? <a class="header-anchor" href="#how-do-i-check-for-updates" aria-label="Permalink to &quot;How do I check for updates?&quot;">​</a></h3><p>Go to <strong>Settings &gt; Updates</strong> and click <strong>Check for Updates</strong>. You can also enable auto-checking in the same section.</p><h3 id="what-do-the-gateway-status-colors-mean" tabindex="-1">What do the Gateway status colors mean? <a class="header-anchor" href="#what-do-the-gateway-status-colors-mean" aria-label="Permalink to &quot;What do the Gateway status colors mean?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Running</td><td>Gateway is active and ready</td></tr><tr><td>Loading</td><td>Gateway is starting</td></tr><tr><td>Error</td><td>Something went wrong — try restarting</td></tr><tr><td>Stopped</td><td>Gateway is not running</td></tr></tbody></table><p>If the Gateway repeatedly fails to start, restart ClawdSaber. If the problem persists, check that the required runtime components are installed (re-run the setup wizard from Settings if needed).</p>',53)])])}const m=a(i,[["render",r]]);export{g as __pageData,m as default};
